#import "recoveryModel.h"

@implementation recoveryModel

+ (NSMutableArray<recoveryModel *> *)allRecs {
    static NSMutableArray *recs = nil;
    if (recs) {
        return recs;
    }
    @synchronized (self) {
        if (!recs) {
            recs = [NSMutableArray array];
            // 尝试从文件加载
            NSArray *savedRecs = [NSArray arrayWithJsonFile:[self filePath] elementClass:[recoveryModel class]];
            if (savedRecs) {
                [recs addObjectsFromArray:savedRecs];
            }
        }
    }
    return recs;
}

- (void)encodeWithCoder:(NSCoder *)coder {
    [coder encodeObject:self.type forKey:@"type"];
    [coder encodeObject:self.date forKey:@"date"];
}

- (nullable instancetype)initWithCoder:(NSCoder *)coder {
    if (self = [super init]) {
        _type = [coder decodeObjectForKey:@"type"];
        _date = [coder decodeObjectForKey:@"date"];
    }
    return self;
}

+ (void)saveRecs {
    [[recoveryModel allRecs] writeToJsonFile:[self filePath]];
}

+ (void)addRecs:(recoveryModel *)rec {
    [[recoveryModel allRecs] addObject:rec];
    [self saveRecs];
}

+ (void)clearRecs {
    [[recoveryModel allRecs] removeAllObjects];
    [self saveRecs];
}

#pragma mark - Private
+ (NSString *)filePath {
    return [NSFileManager documentFilePathWithName:@"Recs.json"];
}

@end
