    self.status = @"Wait";

    if ([title isEqual:@"Chat"]) {
        self.title = @"Chat Recovery";
    } else if ([title isEqual:@"Photo"]) {
        self.title = @"Photo Recovery";
    } else if ([title isEqual:@"contact"]) {
        self.title = @"Address book recovery";
    } else if ([title isEqual:@"Dialogue"]) {
        self.title = @"Dialogue Recovery";
    } else if ([title isEqual:@"friend"]) {
        self.title = @"Friend Recovery";
    } else if ([title isEqual:@"message"]) {
        self.title = @"Message Recovery";
    } else if ([title isEqual:@"call"]) {
        self.title = @"Call Recovery";
    } else {
        self.title = @"Recovery";
    }

    [self updateUI];
}

