    self.titleLabel.text = self.title;
    self.statusLabel.text = self.status;
    self.iconImageView.image = [self iconForType:self.imageName];
}

- (UIImage *)iconForType:(NSString *)type {
    NSString *symbolName = @"doc.text";
    NSString *fallbackName = @"A_service";

    if ([type isEqual:@"Chat"]) {
        symbolName = @"message.fill";
        fallbackName = @"A_Chat";
    } else if ([type isEqual:@"Photo"]) {
        symbolName = @"photo";
        fallbackName = @"A_Photo";
    } else if ([type isEqual:@"contact"]) {
        symbolName = @"person.crop.square";
        fallbackName = @"A_contact";
    }

