    [button showClickedAnimationWithLevel:2];
    [self endEditing:YES];

    _doneButton.layer.hidden = NO;
    _stopButton.layer.hidden = YES;
    [self.player pause];
    //暂停定时器

}

- (void)go:(UIButton *)button {

    [button showClickedAnimationWithLevel:2];
    [self endEditing:YES];

    UIViewController *parentVC = [self findParentViewController];
    ModePickerViewController *modeVc = [[ModePickerViewController alloc] init];

    // 设置回调 block
    __weak typeof(self) weakSelf = self; // 避免循环引用
    modeVc.returnBlock = ^(NSString *returnedValue) {
        __strong typeof(weakSelf) strongSelf = weakSelf;

        // 这里处理回传的数据
        NSLog(@"收到回传值: %@", returnedValue);
        strongSelf.mode = returnedValue; // 保存到属性

        // 刷新UI或其他操作
        //            [strongSelf updateUI];

        if ([returnedValue isEqualToString:@"A_white.mp3"]) {
            self.selectedLabel.text = @"White noise";
        } else if ([returnedValue isEqualToString:@"A_pink.mp3"]) {
            self.selectedLabel.text = @"Pink noise";
        }else{
            self.selectedLabel.text = @"Brown noise";
        }
    };

    [parentVC presentViewController:modeVc animated:YES completion:^{
        [SVProgressHUD dismiss];
    }];
}

- (UIViewController *)findParentViewController {
    UIResponder *responder = self;
    while (responder) {
        if ([responder isKindOfClass:[UIViewController class]]) {
            return (UIViewController *)responder;
        }
        responder = [responder nextResponder];
    }
    return nil;
}

