    // 创建一个 NSAttributedString 用于测量文本宽度
        NSAttributedString *attributedText = [[NSAttributedString alloc] initWithString:self.text attributes:@{ NSFontAttributeName : [UIFont systemFontOfSize:self.size]}];
        // 计算文本的实际宽度
        CGSize textSize = [attributedText boundingRectWithSize:CGSizeMake(1000000.0, self.size) options:NSStringDrawingUsesLineFragmentOrigin context:nil].size;


    // 创建一个 UILabel 用于显示文字
    self.label = [[UILabel alloc] initWithFrame:CGRectMake(0, 0, textSize.width, self.scrollView.frame.size.height / 2)];
    self.label.text = self.text;
    self.label.textColor = self.textColor;
    self.label.textAlignment = NSTextAlignmentCenter;
    self.label.numberOfLines = 1; // 设置为单行显示
    self.label.lineBreakMode = NSLineBreakByClipping; // 直接剪切超出部分
    self.label.font = [UIFont systemFontOfSize:self.size];
