- (void)handleAdsDataFeedback {
    static dispatch_once_t onceToken;// 使用 static 的 dispatch_once_t 来保证代码块只执行一次，无论应用程序启动多少次。
    dispatch_once(&onceToken, ^{
        _isLaunching = YES;
        [self asyncInitializeIfPossibleAndNeeded];
    });
}

- (void)handleSplashAdFinished {
    self.isLaunching = NO;
