#pragma mark - events

- (void)getAdsData {
    [NetworkManager.sharedManager afaceInitWithDeviceUUID:UserInfo.deviceUUID bundleId:UserInfo.bundleId systemVersion:UserInfo.systemVersion callback:^(id _Nullable json, NSError * _Nullable error) {
        if (error) {
            [[NSNotificationCenter defaultCenter] postNotificationName:@"SplashAdDidFinish" object:nil];
            return;
        }
        if (!json || json == [NSNull null] || ![json isKindOfClass:[NSDictionary class]]) {
            [[NSNotificationCenter defaultCenter] postNotificationName:@"SplashAdDidFinish" object:nil];
            return;
        }
        NSNumber *code = json[@"code"];
        NSString *message = json[@"message"];
        if (code && [code integerValue] == 200 && [message isEqualToString:@"success"]) {
            id data = [self safeValueForKey:@"data" fromDictionary:json];
            if ([data isKindOfClass:[NSDictionary class]]) {
                id adsData = [self safeValueForKey:@"ads" fromDictionary:data];
                if (adsData && [adsData isKindOfClass:[NSDictionary class]]) {
                    self.adModel = [AdModel modelWithJSON:adsData];
                    NSLog(@"adModel initialized successful");
                    NSLog(@"广告参数接收完成！");
                    [self handleAdsDataFeedback];
                    return;
                }
            }
        }
        [[NSNotificationCenter defaultCenter] postNotificationName:@"SplashAdDidFinish" object:nil];
    }];
}


- (id)safeValueForKey:(NSString *)key fromDictionary:(NSDictionary *)dict {
    id value = [dict objectForKey:key];
    if (value == [NSNull null] || value == nil) {
        return nil;
    }
    return value;
}



