        [[NSNotificationCenter defaultCenter] addObserver:self
                                                         selector:@selector(backgroundMusicDidFinish:)
                                                             name:AVPlayerItemDidPlayToEndTimeNotification
                                                           object:item];

        // 成功音效
        NSURL *successURL = [[NSBundle mainBundle] URLForResource:@"A_Success_sound" withExtension:@"mp3"];
        _successPlayer = [[AVAudioPlayer alloc] initWithContentsOfURL:successURL error:nil];
        _successPlayer.delegate = nil; // 不需要循环

        // 删除音效
